import{c as i,Q as t,j as o,m as n}from"./chunks/framework.BPKcPtvA.js";const m=JSON.parse('{"title":"How do I configure billing for a customer?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/admin/configure-customer-billing.md","filePath":"guide/recipes/admin/configure-customer-billing.md","lastUpdated":1779094756000}'),r={name:"guide/recipes/admin/configure-customer-billing.md"};function l(a,e,s,c,u,g){return t(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="how-do-i-configure-billing-for-a-customer" tabindex="-1">How do I configure billing for a customer? <a class="header-anchor" href="#how-do-i-configure-billing-for-a-customer" aria-label="Permalink to &quot;How do I configure billing for a customer?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p><strong>Platform Admin</strong> or <strong>Finance Admin</strong></p></div><p>Customer billing settings include plan, payment terms, billing contact, currency, and any custom rates. All invoice generation flows through these settings.</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Open <strong>Finance → Finance Customers</strong> and click the customer.</li><li>Switch to the <strong>Billing Setup</strong> tab.</li><li>In the <strong>Production Billing</strong> section, set: <ul><li><strong>Plan</strong> — pick from published or custom plans.</li><li><strong>Billing cycle</strong> — monthly, quarterly, or annual.</li><li><strong>Payment terms</strong> — Net 7 / 15 / 30 / 60.</li><li><strong>Billing contact email</strong> — recipient of invoices.</li><li><strong>Currency</strong> — fixed for the customer&#39;s lifetime; ask engineering if you need to change it.</li></ul></li><li>Click <strong>Save</strong>.</li></ol><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><p>The next invoice cycle uses the new settings. Existing invoices are unaffected. The change is recorded in audit so you can trace plan/term history.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./configure-non-prod-billing">How do I configure non-production billing?</a></li><li><a href="./create-custom-plan">How do I create a custom plan?</a></li><li><a href="./issue-credit">How do I issue a credit?</a></li></ul>',9)])])}const h=i(r,[["render",l]]);export{m as __pageData,h as default};
